package com.tuapp.clientesimport android.os.Bundleimport android.widget.Buttonimport android.widget.EditTextimport androidx.appcompat.app.AppCompatActivityclass AddEditActivity : AppCompatActivity() {    override fun onCreate(savedInstanceState: Bundle?) {        super.onCreate(savedInstanceState)        setContentView(R.layout.activity_add_edit)        val etNombre = findViewById<EditText>(R.id.etNombre)        val etTelefono = findViewById<EditText>(R.id.etTelefono)        val etEmail = findViewById<EditText>(R.id.etEmail)        val btnGuardar = findViewById<Button>(R.id.btnGuardar)        btnGuardar.setOnClickListener {            val nombre = etNombre.text.toString().trim()            val telefono = etTelefono.text.toString().trim()            val email = etEmail.text.toString().trim()            if (nombre.isNotEmpty() && telefono.isNotEmpty()) {                val dbHelper = DatabaseHelper(this)                dbHelper.insertarCliente(nombre, telefono, email)                finish()            }        }    }}
